"use strict";

const path = require( 'path' );
const _ = require( 'lodash' );
const React = require( 'react' );
const ReactDOM = require( 'react-dom/server' );
const { StaticRouter } = require( 'react-router-dom' );
const { createMemoryHistory } = require( 'history' );
const { ChunkExtractor } = require( '@loadable/server' );
const { __SECRET_INTERNALS_DO_NOT_USE_OR_YOU_WILL_BE_FIRED: LoadableSecret } = require( '@loadable/component' );
const { matchRoutes } = require( '@openagenda/react-utils/dist/asyncMatchRoutes' );
const ScrollToTop = require( '@openagenda/react-utils/dist/ScrollToTop' );
const RouterTrigger = require( '@openagenda/react-utils/dist/RouterTrigger' );
const homeMw = require( '@openagenda/home/dist/middleware' );
const createHomeApp = require( '@openagenda/home/dist/client/app' );
const createUserSettingsApp = require( '@openagenda/user-apps/dist/app' );
const createAgendaSettingsNewApp = require( '@openagenda/agenda-settings/dist/client/createApp' );
const { Html, HeaderManager, Header } = require( '@openagenda/react-layouts' );

const { Context: LoadableContext } = LoadableSecret;
const phpPrefix = process.env.NODE_ENV ? '/frontend_dev.php' : '';

module.exports = function match( { apiRoot, hasInboxNews } ) {
  return async ( req, res, next ) => {
    try {
      // We create an extractor from the statsFile (generated by webpack loadable plugin)
      const extractor = new ChunkExtractor( {
        statsFile: path.join( __dirname, '/dist/loadable-stats.json' ),
        entrypoints: [ 'webapp' ] }
      );

      const lang = req.lang || 'fr';
      const history = createMemoryHistory( { initialEntries: [ req.originalUrl ] } );

      const apps = {
        home: createHomeApp( {
          req,
          // Header: () => React.createElement( HeaderSelector, { type: 'main' } ),
          history,
          initialState: {
            settings: {
              prefix: '/home',
              apiRoot,
              lang,
              perPageLimit: homeMw.getConfig().mw.limit,
              isNew: _.get( req, 'user.isNew' ),
              displayLegacyMessageTab: false,
              userId: _.get( req, 'user.id' ),
              userUid: _.get( req, 'user.uid' )
            },
            res: {
              agendas: {
                contribute: '/:slug/contribute',
                create: '/new',
                list: '/home/agendas',
                show: '/:slug',
                showPrivate: '/:slug.prv',
                addEvent: `${phpPrefix}/:slug/addevent`,
                moderate: `${phpPrefix}/:slug/admin`,
                contact: '/:slug/contact'
              },
              events: {
                list: '/home/events.json',
                show: '/:slug/events/:eventSlug',
                showPrivate: '/:slug.prv/events/:eventSlug',
                showWithoutAgenda: '/events/:eventSlug',
                edit: '/:slug/event/:eventSlug/edit'
              },
              messages: '/home/messages',
              notifs: '/home/notifications',
              search: '/agendas'
            }
          }
        } ),
        userSettings: createUserSettingsApp( {
          req,
          history,
          initialState: {
            settings: {
              prefix: '/settings',
              apiRoot,
              lang
            },
            res: {
              getMe: '/users/me',
              updateProfile: '/users/me',
              deleteAccount: '/users/me',
              changeEmail: '/users/me/requestChangeEmail',
              changePassword: '/users/me/changePassword',
              generateApiKey: '/users/me/generateApiKey',
              uploadProfileImage: '/users/me/setImageProfile',
              removeProfileImage: '/users/me/clearImageProfile'
            }
          }
        } ),
        agendaSettingsNew: createAgendaSettingsNewApp( {
          req,
          history,
          initialState: {
            settings: {
              prefix: '/new',
              apiRoot,
              lang
            },
            res: {
              create: '/new',
              slugAvailable: '/agendas/slugs/available',
              onCreated: '/:slug/admin/getting-started'
            }
          }
        } )
      };

      // Triggers hooks
      await Promise.all(
        Object.values( apps )
          .filter( v => v.triggerHooks )
          .map( v => v
            .triggerHooks()
            .catch( err => console.log( `Error in triggerHooks:`, err ) )
          )
      );

      // Not found
      const notFound = Object.values( apps )
        .every( app =>
          !( app.routes && matchRoutes( app.routes, history.location.pathname ).length )
        );

      if ( notFound ) {
        return next();
      }

      // Check if redirect in hooks
      if ( redirectIfNeeded( req, res, history ) ) {
        return;
      }

      // Create store for the header
      const headerStore = HeaderManager.createStore( {
        header: {
          apiRoot,
          user: req.user,
          notifications: {
            // counter: req.user ? await notificationsCounter( req ) : null
          },
          inbox: {
            hasNew: req.user ? await hasInboxNews( req ) : null
          }
        }
      } );

      const triggerHooks = () => Promise.all(
        Object.values( apps ).map( app => app.triggerHooks() )
      );

      const staticContext = {};

      const content = ReactDOM.renderToString( React.createElement(
        HeaderManager,
        { store: headerStore },
        React.createElement(
          LoadableContext.Provider,
          { value: extractor },
          React.createElement(
            StaticRouter,
            { location: req.originalUrl, context: staticContext },
            React.createElement(
              ScrollToTop,
              null,
              React.createElement(
                RouterTrigger,
                { trigger: triggerHooks },
                Object.values( apps ).map( ( { content } ) => content )
              )
            )
          )
        )
      ) );

      if ( staticContext.url ) {
        return res.redirect( staticContext.status || 302, staticContext.url );
      }

      // Check if location change anywhere else
      if ( redirectIfNeeded( req, res, history ) ) {
        return;
      }

      // Get initialState
      const initialState = _.mapValues( apps, app => {
        const state = app.store.getState();

        // Avoid all settings.apiRoot
        if ( _.get( state, 'settings.apiRoot' ) ) {
          _.set( state, 'settings.apiRoot', '' );
        }

        return state;
      } );

      initialState.header = headerStore.getState();
      _.set( initialState.header, 'header.apiRoot', '' );

      const headerType = headerStore.getState().header.type;
      const headerHtml = ReactDOM.renderToString( React.createElement(
        Header,
        { store: headerStore, type: headerType }
      ) );

      // Send Html
      const html = React.createElement( Html, { content: headerHtml + content, lang, initialState, extractor } );
      res.status( 200 ).send( `<!doctype html>${ReactDOM.renderToString( html )}` );
    } catch ( e ) {
      next( e );
    }
  };
};

function redirectIfNeeded( req, res, history ) {
  const { pathname, search } = history.location;

  if ( decodeURIComponent( req.originalUrl ) !== decodeURIComponent( pathname + search ) ) {
    res.redirect( 302, pathname + search );
    return true;
  }
}
